class SideOutputProcessor:
    def __init__(self, watermark_lag_seconds=60):
        self.watermark_lag = watermark_lag_seconds
        self.main_output = []
        self.late_output = []     # side output for late events

    def process(self, event, current_watermark):
        event_time = event['event_time']
        # Determine if late relative to its window
        window_end = self._get_window_end(event_time)

        if window_end.timestamp() < current_watermark.timestamp():
            self.late_output.append({
                **event,
                'lateness_seconds': (
                    current_watermark - window_end
                ).total_seconds()
            })
        else:
            self.main_output.append(event)

    def _get_window_end(self, event_time, window_size=60):
        ts = event_time.timestamp()
        ws = int(ts // window_size) * window_size
        return datetime.utcfromtimestamp(ws + window_size)
